    diveContent:
      '<p class="ql-align-justify"><a href="https://www.ibef.org/indian-exports/india-australia-trade" rel="noopener noreferrer" target="_blank" style="background-color: transparent; color: rgb(17, 85, 204);">All about Trade</a><span style="background-color: transparent; color: rgb(0, 0, 0);">: The bilateral trade between India and Australia in FY23 stood at US$ 25.9 billion, up from $18 billion in 2020.</span></p><p class="ql-align-justify"><a href="https://aii.unimelb.edu.au/wp-content/uploads/2023/11/AII-AusIndia-Education-Snapshot.pdf" rel="noopener noreferrer" target="_blank" style="background-color: transparent; color: rgb(17, 85, 204);">Education Connection</a><span style="background-color: transparent; color: rgb(0, 0, 0);">: As of 2021, Australian universities had 432 active formal partnership agreements with Indian higher education institutions.</span></p><p class="ql-align-justify"><a href="https://economictimes.indiatimes.com/news/economy/foreign-trade/india-australia-relations-preparing-for-ceca/articleshow/107101205.cms" rel="noopener noreferrer" target="_blank" style="background-color: transparent; color: rgb(17, 85, 204);">Mates beyond FTA</a><span style="background-color: transparent; color: rgb(0, 0, 0);">: India and Australia are preparing for Comprehensive Economic Cooperation Agreement</span></p>',
